$excludedMods = @(
    "Cobblemon-fabric-1.6.1+1.21.1.jar",   # RemplacÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â© par 1.7.3
    "fabric-api-0.116.7+1.21.1.jar"         # RemplacÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â© par 0.116.11
)

$requiredMods = Get-ChildItem "$serverRoot\forgemods\required\" -Filter "*.jar" | Sort-Object Name
