Write-Host "[4/5] Scan des mods optionnels activÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â©s (optionalon/)..." -ForegroundColor Yellow

$optionalOnMods = Get-ChildItem "$serverRoot\forgemods\optionalon\" -Filter "*.jar" | Sort-Object Name
foreach ($mod in $optionalOnMods) {
    Write-Host "  [ON]   $($mod.Name)" -ForegroundColor Cyan -NoNewline
    $md5 = Get-MD5 $mod.FullName
    Write-Host " ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ $md5" -ForegroundColor DarkGray

