Write-Host ""
Write-Host "Assemblage du JSON..." -ForegroundColor Yellow

$distribution = [ordered]@{
    version = "1.0.0"
    rss     = "https://apk.nerysia.fr/utopia-laucher/feed.xml"
    servers = @(
        [ordered]@{
            id               = "Utopia-1.21.1"
            name             = "Utopia (Minecraft 1.21.1)"
            description      = "Utopia Running Minecraft 1.21.1 (NeoForge 21.1.233)"
            icon             = "https://apk.nerysia.fr/Logo.png"
            version          = $newVersion
            address          = "node.hloureiro.fr:45536"
            minecraftVersion = "1.21.1"
            mainServer       = $true
            autoconnect      = $false
            modules          = $modules.ToArray()
        }
    )
}

$json = $distribution | ConvertTo-Json -Depth 20 -Compress:$false

# ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â°crire SANS BOM (UTF-8 sans BOM) ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â important pour que Node.js puisse parser le JSON
$utf8NoBom = New-Object System.Text.UTF8Encoding $false
[System.IO.File]::WriteAllText($outputFile, $json, $utf8NoBom)

Write-Host ""
Write-Host "=== UPLOAD vers le serveur ===" -ForegroundColor Yellow
$serverDest = "Y:\apk\utopia-laucher\distribution.json"
if (Test-Path (Split-Path $serverDest)) {
    Copy-Item $outputFile $serverDest -Force
    Write-Host "  Upload OK : $serverDest" -ForegroundColor Green
} else {
    Write-Host "  Serveur non monte (Y:\apk introuvable) - upload manuel requis" -ForegroundColor Yellow
}

Write-Host ""
Write-Host "=== TERMINE ===" -ForegroundColor Green
Write-Host "Fichier genere : $outputFile" -ForegroundColor White
Write-Host "Version modpack: $newVersion" -ForegroundColor White
Write-Host "Total modules  : $($modules.Count)" -ForegroundColor White


